      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const repository = require('./repository');

router.get('/', (req, res) => {
  const projects = repository.getAll();
  res.status(200).json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: { code: 'invalid_input', message: 'Name is required' } });
  if (repository.getAll().some(p => p.name === name)) return res.status(409).json({ error: { code: 'duplicate_project', message: 'Project with this name already exists' } });
  const project = repository.create(name);
  res.status(201).json({ project });
});

router.get('/:projectId', (req, res) => {
  const project = repository.getById(req.params.projectId);
  if (!project) return res.status(404).json({ error: { code: 'not_found', message: 'Project not found' } });
  res.status(200).json({ project });
});

module.exports = router;
