      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const projectRepository = require('../projects/repository');
const repository = require('./repository');

router.get('/:projectId/tasks', (req, res) => {
  const { status } = req.query;
  const tasks = repository.getAll(req.params.projectId);
  if (status) {
    res.status(200).json({ tasks: tasks.filter(t => t.status === status) });
  } else {
    res.status(200).json({ tasks });
  }
});

router.post('/:projectId/tasks', (req, res) => {
  const { title } = req.body;
  if (!title) return res.status(400).json({ error: { code: 'invalid_input', message: 'Title is required' } });
  const project = projectRepository.getById(req.params.projectId);
  if (!project) return res.status(404).json({ error: { code: 'not_found', message: 'Project not found' } });
  const task = repository.create(req.params.projectId, title);
  res.status(201).json({ task });
});

router.patch('/:projectId/tasks/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status) return res.status(400).json({ error: { code: 'invalid_input', message: 'Status is required' } });
  const task = repository.updateStatus(req.params.projectId, req.params.taskId, status);
  if (!task) return res.status(404).json({ error: { code: 'not_found', message: 'Task not found' } });
  res.status(200).json({ task });
});

module.exports = router;
