      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const projectRepository = require('../projects/repository');
const taskRepository = require('../tasks/repository');
const repository = require('./repository');

router.get('/:projectId/tasks/:taskId/comments', (req, res) => {
  const comments = repository.getAll(req.params.projectId, req.params.taskId);
  res.status(200).json({ comments });
});

router.post('/:projectId/tasks/:taskId/comments', (req, res) => {
  const { message } = req.body;
  if (!message) return res.status(400).json({ error: { code: 'invalid_input', message: 'Message is required' } });
  const project = projectRepository.getById(req.params.projectId);
  if (!project) return res.status(404).json({ error: { code: 'not_found', message: 'Project not found' } });
  const task = taskRepository.getById(req.params.projectId, req.params.taskId);
  if (!task) return res.status(404).json({ error: { code: 'not_found', message: 'Task not found' } });
  const comment = repository.create(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

module.exports = router;
